import sqlite3
from pathlib import Path

import pytest

ROOT = Path(__file__).resolve().parents[1]


def expand_sql(relative_path):
    path = (ROOT / relative_path).resolve()
    if path == ROOT or ROOT not in path.parents:
        raise ValueError("SQL path escapes case repository")
    expanded = []
    for line in path.read_text(encoding="utf-8").splitlines():
        parts = line.strip().split(maxsplit=1)
        if parts and parts[0] == ".bail":
            continue
        if parts and parts[0] == ".read":
            if len(parts) != 2:
                raise ValueError("missing .read target")
            expanded.append(expand_sql(parts[1]))
        else:
            expanded.append(line)
    return "\n".join(expanded)


def run_sql(script_name):
    connection = sqlite3.connect(":memory:")
    try:
        connection.executescript(expand_sql(f"tests/{script_name}"))
    finally:
        connection.close()


def test_final_sql_contracts():
    for script_name in ("final_schema.sql", "final_query.sql", "final.sql"):
        run_sql(script_name)


def test_final_schema_rejects_overlap_created_by_update():
    connection = sqlite3.connect(":memory:")
    try:
        connection.executescript(expand_sql("db/schema.sql"))
        connection.executescript(
            """
            INSERT INTO prices(sku, amount_cents, valid_from, valid_to) VALUES
              ('update-probe', 100, '2027-06-01T00:00:00Z', '2027-06-10T00:00:00Z'),
              ('update-probe', 120, '2027-06-20T00:00:00Z', '2027-07-01T00:00:00Z');
            """
        )
        with pytest.raises(sqlite3.IntegrityError):
            connection.execute(
                "UPDATE prices SET valid_from = '2027-06-05T00:00:00Z' WHERE amount_cents = 120"
            )
    finally:
        connection.close()
